   221→        const text = data.message;
   222→        if (text) {
   223→          result.formattedOutput = `${this.colors.magenta}[system]${this.colors.reset} ${text}`;
   224→        }
   225→        break;
   226→      }
   227→
   228→      case 'result': {
   229→        const cost = data.cost_usd;
   230→        const duration = data.duration_ms;
   231→        const parts = [];
   232→        result.actions.push({ action: 'stop_spinner' });
   233→
   234→        if (cost) {
   235→          parts.push(`cost: $${cost}`);
   236→          result.actions.push({ action: 'add_cost', cost: parseFloat(cost) });
   237→        }
   238→        if (duration) {
   239→          parts.push(`duration: ${this.formatDuration(duration)}`);
   240→        }
   241→        if (parts.length > 0) {
   242→          result.formattedOutput = `${this.colors.dim}[stats] ${parts.join(', ')}${this.colors.reset}`;
   243→        }
   244→        break;
   245→      }
   246→
   247→      default: {
   248→        if (data.subagent) {
   249→          result.formattedOutput = `${this.colors.magenta}[subagent]${this.colors.reset} ${data.subagent}`;
   250→        }
   251→        break;
   252→      }
   253→    }
   254→
   255→    return result;
   256→  }
   257→}
