#!/usr/bin/env node
/**
 * Tests for Ralph Session Logger
 *
 * Validates that stream-json parsing extracts correct model/cost/token/tool data,
 * that session files are initialized and updated correctly, and that git helpers
 * behave safely when a repo is not present.
 *
 * Uses Node.js built-in modules only — zero external dependencies.
 */

'use strict';

const assert = require('assert');
const fs = require('fs');
const path = require('path');
const os = require('os');
const { spawnSync } = require('child_process');

const SESSION_LOGGER = path.join(__dirname, '../lib/session-logger.js');

// ─── helpers ──────────────────────────────────────────────────────────────────

function tmpDir() {
  return fs.mkdtempSync(path.join(os.tmpdir(), 'session-logger-test-'));
}

function writeStreamJson(dir, events) {
  const p = path.join(dir, 'stream.json');
  fs.writeFileSync(p, events.map(e => JSON.stringify(e)).join('\n') + '\n', 'utf8');
  return p;
}

function runLogger(args, cwd) {
  const result = spawnSync(process.execPath, [SESSION_LOGGER, ...args], {
    cwd: cwd || process.cwd(),
    encoding: 'utf8',
  });
  return result;
}

function readSession(dir, sessionId) {
  const p = path.join(dir, 'logs', 'sessions', `${sessionId}.json`);
  return JSON.parse(fs.readFileSync(p, 'utf8'));
}

// ─── test suite ───────────────────────────────────────────────────────────────

let passed = 0;
let failed = 0;

function test(name, fn) {
  try {
    fn();
    console.log(`✓ ${name}`);
    passed++;
  } catch (err) {
    console.log(`✗ ${name}`);
    console.log(`  ${err.message}`);
    failed++;
  }
}

// ─── init command ─────────────────────────────────────────────────────────────

test('init creates session file with correct metadata', () => {
  const dir = tmpDir();
  const r = runLogger([
    'init',
    '--session-id', 'test-session-001',
    '--branch', 'ralph/workspace-test',
    '--original-branch', 'main',
    '--mode', 'build',
    '--model', 'claude-sonnet-4-6',
    '--max-iterations', '5',
    '--head-at-start', 'abc123',
  ], dir);

  assert.strictEqual(r.status, 0, `exit ${r.status}: ${r.stderr}`);

  const session = readSession(dir, 'test-session-001');
  assert.strictEqual(session.session_id, 'test-session-001');
  assert.strictEqual(session.branch, 'ralph/workspace-test');
  assert.strictEqual(session.original_branch, 'main');
  assert.strictEqual(session.mode, 'build');
  assert.strictEqual(session.model, 'claude-sonnet-4-6');
  assert.strictEqual(session.max_iterations, 5);
  assert.strictEqual(session.head_at_start, 'abc123');
  assert.deepStrictEqual(session.iterations, []);
  assert(session.started_at.match(/^\d{4}-\d{2}-\d{2}T/));
});

test('init creates parent directories automatically', () => {
  const dir = tmpDir();
  const r = runLogger([
    'init', '--session-id', 'mkdir-test',
    '--branch', 'b', '--original-branch', 'main',
    '--mode', 'build', '--model', 'm',
  ], dir);
  assert.strictEqual(r.status, 0, r.stderr);
  assert(fs.existsSync(path.join(dir, 'logs', 'sessions', 'mkdir-test.json')));
});

test('init fails without --session-id', () => {
  const dir = tmpDir();
  const r = runLogger(['init', '--branch', 'b'], dir);
  assert.notStrictEqual(r.status, 0);
});

// ─── iteration command ────────────────────────────────────────────────────────

function setupSession(dir, sessionId) {
  runLogger([
    'init', '--session-id', sessionId,
    '--branch', 'ralph/test', '--original-branch', 'main',
    '--mode', 'build', '--model', 'claude-test',
    '--head-at-start', '000000',
  ], dir);
}

test('iteration appends data parsed from stream-json', () => {
  const dir = tmpDir();
  setupSession(dir, 'iter-test-001');

  const streamFile = writeStreamJson(dir, [
    { type: 'message_start', message: { model: 'claude-sonnet-4-6', usage: { input_tokens: 1000 } } },
    { type: 'content_block_start', content_block: { type: 'tool_use', name: 'Bash' } },
    { type: 'content_block_start', content_block: { type: 'tool_use', name: 'Read' } },
    { type: 'tool_use', name: 'Edit', input: {} },
    { type: 'message_delta', usage: { output_tokens: 250 } },
    { type: 'result', cost_usd: '0.0042', usage: { input_tokens: 1000, output_tokens: 250 } },
  ]);

  const r = runLogger([
    'iteration',
    '--session-id', 'iter-test-001',
    '--iteration', '1',
    '--model', 'claude-sonnet-4-6',
    '--duration-ms', '12345',
    '--prev-commit', '',
    streamFile,
  ], dir);

  assert.strictEqual(r.status, 0, `exit ${r.status}: ${r.stderr}`);

  const session = readSession(dir, 'iter-test-001');
  assert.strictEqual(session.iterations.length, 1);

  const it = session.iterations[0];
  assert.strictEqual(it.iteration, 1);
  assert.strictEqual(it.model, 'claude-sonnet-4-6');
  assert.strictEqual(it.cost_usd, 0.0042);
  assert.strictEqual(it.input_tokens, 1000);
  assert.strictEqual(it.output_tokens, 250);
  assert(it.tools_called.includes('Bash'));
  assert(it.tools_called.includes('Read'));
  assert(it.tools_called.includes('Edit'));
  assert.strictEqual(it.duration_ms, 12345);
  assert(it.timestamp.match(/^\d{4}-\d{2}-\d{2}T/));
});

test('iteration deduplicates tool names from content_block_start and tool_use', () => {
  const dir = tmpDir();
  setupSession(dir, 'dedup-test');

  const streamFile = writeStreamJson(dir, [
    { type: 'content_block_start', content_block: { type: 'tool_use', name: 'Bash' } },
    { type: 'tool_use', name: 'Bash', input: {} },
    { type: 'tool_use', name: 'Read', input: {} },
  ]);

  runLogger([
    'iteration', '--session-id', 'dedup-test',
    '--iteration', '1', '--duration-ms', '100', '--prev-commit', '',
    streamFile,
  ], dir);

  const session = readSession(dir, 'dedup-test');
  const tools = session.iterations[0].tools_called;
  const unique = new Set(tools);
  assert.strictEqual(tools.length, unique.size, 'tool names should be deduplicated');
  assert(tools.includes('Bash'));
  assert(tools.includes('Read'));
});

test('multiple iterations accumulate correctly', () => {
  const dir = tmpDir();
  setupSession(dir, 'multi-iter');

  const streamFile = writeStreamJson(dir, [
    { type: 'result', cost_usd: '0.001' },
  ]);

  runLogger(['iteration', '--session-id', 'multi-iter', '--iteration', '1',
    '--duration-ms', '1000', '--prev-commit', '', streamFile], dir);
  runLogger(['iteration', '--session-id', 'multi-iter', '--iteration', '2',
    '--duration-ms', '2000', '--prev-commit', '', streamFile], dir);

  const session = readSession(dir, 'multi-iter');
  assert.strictEqual(session.iterations.length, 2);
  assert.strictEqual(session.iterations[0].iteration, 1);
  assert.strictEqual(session.iterations[1].iteration, 2);
});

test('iteration handles missing stream file gracefully', () => {
  const dir = tmpDir();
  setupSession(dir, 'no-stream');

  const r = runLogger([
    'iteration', '--session-id', 'no-stream',
    '--iteration', '1', '--duration-ms', '100', '--prev-commit', '',
    '/nonexistent/stream.json',
  ], dir);

  assert.strictEqual(r.status, 0, `should not fail on missing stream file: ${r.stderr}`);

  const session = readSession(dir, 'no-stream');
  const it = session.iterations[0];
  assert.strictEqual(it.cost_usd, null);
  assert.deepStrictEqual(it.tools_called, []);
});

test('iteration fails without --session-id', () => {
  const dir = tmpDir();
  const r = runLogger(['iteration', '--iteration', '1'], dir);
  assert.notStrictEqual(r.status, 0);
});

test('iteration fails when session file does not exist', () => {
  const dir = tmpDir();
  const r = runLogger(['iteration', '--session-id', 'ghost', '--iteration', '1'], dir);
  assert.notStrictEqual(r.status, 0);
});

// ─── stream-json parsing edge cases ──────────────────────────────────────────

test('stream parsing ignores non-JSON lines', () => {
  const dir = tmpDir();
  setupSession(dir, 'nonjson-test');

  const p = path.join(dir, 'mixed.json');
  fs.writeFileSync(p,
    'plain text line\n' +
    JSON.stringify({ type: 'result', cost_usd: '0.0099' }) + '\n' +
    '{ broken json\n',
    'utf8'
  );

  runLogger([
    'iteration', '--session-id', 'nonjson-test',
    '--iteration', '1', '--duration-ms', '100', '--prev-commit', '', p,
  ], dir);

  const session = readSession(dir, 'nonjson-test');
  assert.strictEqual(session.iterations[0].cost_usd, 0.0099);
});

test('stream parsing handles empty file', () => {
  const dir = tmpDir();
  setupSession(dir, 'empty-stream');

  const p = path.join(dir, 'empty.json');
  fs.writeFileSync(p, '', 'utf8');

  const r = runLogger([
    'iteration', '--session-id', 'empty-stream',
    '--iteration', '1', '--duration-ms', '100', '--prev-commit', '', p,
  ], dir);

  assert.strictEqual(r.status, 0);
  const session = readSession(dir, 'empty-stream');
  assert.deepStrictEqual(session.iterations[0].tools_called, []);
});

// ─── check-spend command ──────────────────────────────────────────────────────

function setupSessionWithCosts(dir, sessionId, costs) {
  setupSession(dir, sessionId);
  for (let i = 0; i < costs.length; i++) {
    const streamFile = writeStreamJson(dir, [
      { type: 'result', cost_usd: String(costs[i]) },
    ]);
    runLogger([
      'iteration', '--session-id', sessionId,
      '--iteration', String(i + 1), '--duration-ms', '100', '--prev-commit', '',
      streamFile,
    ], dir);
  }
}

test('check-spend exits 0 when total is under ceiling', () => {
  const dir = tmpDir();
  setupSessionWithCosts(dir, 'spend-under', [0.01, 0.02]);

  const r = runLogger([
    'check-spend', '--session-id', 'spend-under', '--ceiling', '0.10',
  ], dir);

  assert.strictEqual(r.status, 0, `expected exit 0: ${r.stderr}`);
  assert(r.stdout.includes('WITHIN'), `expected WITHIN in output: ${r.stdout}`);
});

test('check-spend exits 2 when total meets or exceeds ceiling', () => {
  const dir = tmpDir();
  setupSessionWithCosts(dir, 'spend-over', [0.05, 0.06]);

  const r = runLogger([
    'check-spend', '--session-id', 'spend-over', '--ceiling', '0.10',
  ], dir);

  assert.strictEqual(r.status, 2, `expected exit 2: ${r.stderr}`);
  assert(r.stdout.includes('EXCEEDED'), `expected EXCEEDED in output: ${r.stdout}`);
});

test('check-spend exits 0 with no ceiling provided', () => {
  const dir = tmpDir();
  setupSessionWithCosts(dir, 'spend-no-ceiling', [0.99]);

  const r = runLogger([
    'check-spend', '--session-id', 'spend-no-ceiling',
  ], dir);

  assert.strictEqual(r.status, 0, `expected exit 0: ${r.stderr}`);
  assert(r.stdout.includes('WITHIN'), `expected WITHIN in output: ${r.stdout}`);
});

test('check-spend handles null cost_usd iterations gracefully', () => {
  const dir = tmpDir();
  setupSession(dir, 'spend-null');

  const emptyStream = writeStreamJson(dir, []);
  runLogger([
    'iteration', '--session-id', 'spend-null',
    '--iteration', '1', '--duration-ms', '100', '--prev-commit', '', emptyStream,
  ], dir);

  const r = runLogger([
    'check-spend', '--session-id', 'spend-null', '--ceiling', '0.01',
  ], dir);

  assert.strictEqual(r.status, 0, `null costs should count as 0: ${r.stderr}`);
});

test('check-spend fails when session file not found', () => {
  const dir = tmpDir();
  const r = runLogger(['check-spend', '--session-id', 'ghost-session'], dir);
  assert.notStrictEqual(r.status, 0);
});

test('check-spend fails without --session-id', () => {
  const dir = tmpDir();
  const r = runLogger(['check-spend', '--ceiling', '1.00'], dir);
  assert.notStrictEqual(r.status, 0);
});

// ─── unknown command ──────────────────────────────────────────────────────────

test('unknown command exits non-zero', () => {
  const dir = tmpDir();
  const r = runLogger(['bogus'], dir);
  assert.notStrictEqual(r.status, 0);
});

// ─── results ──────────────────────────────────────────────────────────────────

console.log(`\nTest Results: ${passed} passed, ${failed} failed`);
if (failed > 0) process.exit(1);

